from functools import reduce

N = int(input())
M = int(input())

step_counts = [int(input()) for i in range(N)]

def is_valid(step_count):
    return step_count >= M

def categorize(step_count):
    if step_count >= 10000:
        return 'Active'
    elif step_count >= 5000:
        return 'Moderately Active'
    else:
        return 'Sedentary'

def sum_active_steps(total, step_count):
    if step_count >= 10000:
        return total + step_count
    return total

valid_steps = filter(is_valid, step_counts)
activity_levels = list(map(categorize, valid_steps))
total_active_steps = reduce(sum_active_steps, filter(is_valid, step_counts), 0)

print(activity_levels, total_active_steps)
